import {
  useState,
  useRef,
  useEffect,
  forwardRef,
  useCallback,
} from 'react'
import { useCreateTodo } from '../hooks/useTodos'

function assignRef<T> (el: T | null, ref: React.Ref<T> | undefined) {
  if (!ref) return
  if (typeof ref === 'function') ref(el)
  else (ref as React.MutableRefObject<T | null>).current = el
}

interface TodoInputProps {
  onError?: (message: string) => void
}

export const TodoInput = forwardRef<HTMLInputElement, TodoInputProps>(
  function TodoInput ({ onError }, ref) {
    const [text, setText] = useState('')
    const localRef = useRef<HTMLInputElement>(null)
    const createTodo = useCreateTodo(onError)

    const setRefs = useCallback(
      (node: HTMLInputElement | null) => {
        localRef.current = node
        assignRef(node, ref)
      },
      [ref],
    )

    useEffect(() => {
      localRef.current?.focus()
    }, [])

    const handleKeyDown = (e: React.KeyboardEvent<HTMLInputElement>) => {
      if (e.key === 'Enter') {
        const trimmed = text.trim()
        if (!trimmed) return
        createTodo.mutate(trimmed)
        setText('')
      } else if (e.key === 'Escape') {
        setText('')
      }
    }

    return (
      <input
        ref={setRefs}
        type="text"
        value={text}
        onChange={(e) => setText(e.target.value)}
        onKeyDown={handleKeyDown}
        placeholder="What needs doing?"
        aria-label="Add a new task"
        className="min-h-[44px] w-full box-border bg-transparent border-l-2 border-accent pl-5 py-4 text-[1.125rem] font-light text-text-primary placeholder:text-text-placeholder outline-none focus:ring-2 focus:ring-accent focus:ring-offset-2 focus:ring-offset-bg"
      />
    )
  },
)

import {
  type MouseEvent,
  type KeyboardEvent,
  forwardRef,
} from 'react'
import type { Todo } from '../types'

interface TodoItemProps {
  todo: Todo
  onToggle: (id: number, completed: boolean) => void
  onDelete: (id: number) => void
  isExiting?: boolean
  tabIndex?: number
  onRowKeyDown?: (e: KeyboardEvent<HTMLLIElement>) => void
  onDeleteButtonKeyDown?: (e: KeyboardEvent<HTMLButtonElement>) => void
}

export const TodoItem = forwardRef<HTMLLIElement, TodoItemProps>(
  function TodoItem (
    {
      todo,
      onToggle,
      onDelete,
      isExiting = false,
      tabIndex = 0,
      onRowKeyDown,
      onDeleteButtonKeyDown,
    },
    ref,
  ) {
    const formattedDate = new Date(todo.createdAt).toLocaleDateString('en-US', {
      month: 'short',
      day: 'numeric',
      year: 'numeric',
    })

    const handleClick = () => {
      onToggle(todo.id, !todo.completed)
    }

    const handleDelete = (e: MouseEvent<HTMLButtonElement>) => {
      e.stopPropagation()
      onDelete(todo.id)
    }

    const handleDeleteKeyDown = (e: KeyboardEvent<HTMLButtonElement>) => {
      if (e.key === 'Delete' || e.key === 'Backspace') {
        e.preventDefault()
        e.stopPropagation()
        onDelete(todo.id)
      }
      onDeleteButtonKeyDown?.(e)
    }

    return (
      <li
        ref={ref}
        role="checkbox"
        aria-checked={todo.completed}
        tabIndex={tabIndex}
        onClick={handleClick}
        onKeyDown={onRowKeyDown}
        className={`group relative flex min-h-[44px] flex-col pl-5 pr-14 py-4 border-l-2 border-transparent lg:hover:border-border lg:hover:bg-surface-hover active:bg-surface-hover cursor-pointer select-none transition-colors duration-300 transition-opacity duration-200 motion-reduce:transition-none outline-none focus:ring-2 focus:ring-accent focus:ring-offset-2 focus:ring-offset-bg ${
          isExiting ? 'opacity-0 pointer-events-none' : 'opacity-100'
        }`}
      >
        <span
          className={`text-[1.125rem] font-light transition-all duration-300 motion-reduce:transition-none ${
            todo.completed
              ? 'text-text-secondary line-through italic'
              : 'text-text-primary'
          }`}
        >
          {todo.text}
        </span>
        <span className="text-[0.6875rem] font-normal uppercase tracking-[0.05em] text-text-placeholder mt-1">
          {formattedDate}
        </span>
        <button
          type="button"
          tabIndex={-1}
          aria-label={`Delete task: ${todo.text}`}
          onClick={handleDelete}
          onKeyDown={handleDeleteKeyDown}
          className="absolute right-2 top-1/2 -translate-y-1/2 w-11 h-11 flex items-center justify-center text-text-secondary text-lg hover:text-text-primary cursor-pointer opacity-100 lg:opacity-0 lg:group-hover:opacity-100 transition-opacity duration-200 motion-reduce:transition-none outline-none focus:ring-2 focus:ring-accent focus:ring-offset-2 focus:ring-offset-bg"
        >
          ×
        </button>
      </li>
    )
  },
)

