import {
  useEffect,
  useLayoutEffect,
  useRef,
  useState,
  type RefObject,
  type KeyboardEvent,
} from 'react'
import { useDeleteTodo, useTodos, useToggleTodo } from '../hooks/useTodos'
import { EmptyState } from './EmptyState'
import { ErrorState } from './ErrorState'
import { LoadingState } from './LoadingState'
import { TodoItem } from './TodoItem'

interface TodoListProps {
  onError?: (message: string) => void
  inputRef?: RefObject<HTMLInputElement | null>
}

const DELETE_FADE_MS = 200

export function TodoList ({ onError, inputRef }: TodoListProps) {
  const { todos, isLoading, isError, isFetching, refetch } = useTodos()
  const toggleTodo = useToggleTodo(onError)
  const deleteTodo = useDeleteTodo(onError)
  const [deletingId, setDeletingId] = useState<number | null>(null)
  const deleteTimerRef = useRef<ReturnType<typeof setTimeout> | null>(null)
  const pendingDeleteIdRef = useRef<number | null>(null)
  const [rovingIndex, setRovingIndex] = useState(0)
  const itemRefs = useRef<(HTMLLIElement | null)[]>([])
  const prevTodosLengthRef = useRef(0)

  useEffect(() => {
    return () => {
      if (deleteTimerRef.current) clearTimeout(deleteTimerRef.current)
    }
  }, [])

  useEffect(() => {
    if (todos.length === 0) return
    setRovingIndex((i) => Math.min(i, todos.length - 1))
  }, [todos.length])

  useLayoutEffect(() => {
    if (todos.length === 0) {
      prevTodosLengthRef.current = 0
      return
    }
    if (todos.length < prevTodosLengthRef.current) {
      const idx = Math.min(rovingIndex, todos.length - 1)
      setRovingIndex(idx)
      queueMicrotask(() => {
        itemRefs.current[idx]?.focus()
      })
    }
    prevTodosLengthRef.current = todos.length
  }, [todos.length, todos, rovingIndex])

  if (isLoading) return <LoadingState />
  if (isError && isFetching) return <LoadingState />
  if (isError) return <ErrorState onRetry={refetch} />
  if (todos.length === 0) return <EmptyState />

  const handleToggle = (id: number, completed: boolean) => {
    toggleTodo.mutate({ id, completed })
  }

  const handleDelete = (id: number) => {
    if (
      deleteTimerRef.current !== null &&
      pendingDeleteIdRef.current !== null &&
      pendingDeleteIdRef.current !== id
    ) {
      const flushedId = pendingDeleteIdRef.current
      clearTimeout(deleteTimerRef.current)
      deleteTimerRef.current = null
      pendingDeleteIdRef.current = null
      deleteTodo.mutate(flushedId)
    } else if (deleteTimerRef.current !== null) {
      clearTimeout(deleteTimerRef.current)
      deleteTimerRef.current = null
      pendingDeleteIdRef.current = null
    }

    pendingDeleteIdRef.current = id
    setDeletingId(id)
    deleteTimerRef.current = setTimeout(() => {
      deleteTimerRef.current = null
      pendingDeleteIdRef.current = null
      deleteTodo.mutate(id, {
        onSettled: () => {
          setDeletingId((current) => (current === id ? null : current))
        },
      })
    }, DELETE_FADE_MS)
  }

  const focusItem = (index: number) => {
    setRovingIndex(index)
    queueMicrotask(() => {
      itemRefs.current[index]?.focus()
    })
  }

  const handleRowKeyDown = (
    e: KeyboardEvent<HTMLLIElement>,
    index: number,
  ) => {
    if (e.key === 'ArrowDown') {
      e.preventDefault()
      if (index < todos.length - 1) focusItem(index + 1)
      return
    }
    if (e.key === 'ArrowUp') {
      e.preventDefault()
      if (index > 0) {
        focusItem(index - 1)
      } else {
        inputRef?.current?.focus()
      }
      return
    }
    if (e.key === ' ' || e.key === 'Enter') {
      e.preventDefault()
      const todo = todos[index]
      handleToggle(todo.id, !todo.completed)
      return
    }
    if (e.key === 'Delete' || e.key === 'Backspace') {
      e.preventDefault()
      handleDelete(todos[index].id)
    }
  }

  return (
    <ul role="list" aria-label="Task list" className="divide-y divide-border">
      {todos.map((todo, index) => (
        <TodoItem
          key={todo.id}
          ref={(el) => {
            itemRefs.current[index] = el
          }}
          todo={todo}
          onToggle={handleToggle}
          onDelete={handleDelete}
          isExiting={deletingId === todo.id}
          tabIndex={index === rovingIndex ? 0 : -1}
          onRowKeyDown={(e) => handleRowKeyDown(e, index)}
        />
      ))}
    </ul>
  )
}

import {
  useEffect,
  useLayoutEffect,
  useRef,
  useState,
  type RefObject,
  type KeyboardEvent,
} from 'react'
import { useDeleteTodo, useTodos, useToggleTodo } from '../hooks/useTodos'
import { EmptyState } from './EmptyState'
import { ErrorState } from './ErrorState'
import { LoadingState } from './LoadingState'
import { TodoItem } from './TodoItem'

interface TodoListProps {
  onError?: (message: string) => void
  inputRef?: RefObject<HTMLInputElement | null>
}

const DELETE_FADE_MS = 200

export function TodoList ({ onError, inputRef }: TodoListProps) {
  const { todos, isLoading, isError, isFetching, refetch } = useTodos()
  const toggleTodo = useToggleTodo(onError)
  const deleteTodo = useDeleteTodo(onError)
  const [deletingId, setDeletingId] = useState<number | null>(null)
  const deleteTimerRef = useRef<ReturnType<typeof setTimeout> | null>(null)
  const pendingDeleteIdRef = useRef<number | null>(null)
  const [rovingIndex, setRovingIndex] = useState(0)
  const itemRefs = useRef<(HTMLLIElement | null)[]>([])
  const prevTodosLengthRef = useRef(0)

  useEffect(() => {
    return () => {
      if (deleteTimerRef.current) clearTimeout(deleteTimerRef.current)
    }
  }, [])

  useLayoutEffect(() => {
    if (todos.length === 0) {
      prevTodosLengthRef.current = 0
      return
    }
    const prevLen = prevTodosLengthRef.current
    const shrink = todos.length < prevLen
    prevTodosLengthRef.current = todos.length

    setRovingIndex((i) => {
      const next = Math.min(i, todos.length - 1)
      if (shrink) {
        queueMicrotask(() => {
          itemRefs.current[next]?.focus()
        })
      }
      return next
    })
  }, [todos.length, todos])

  const handleToggle = (id: number, completed: boolean) => {
    toggleTodo.mutate({ id, completed })
  }

  const handleDelete = (id: number) => {
    if (
      deleteTimerRef.current !== null &&
      pendingDeleteIdRef.current !== null &&
      pendingDeleteIdRef.current !== id
    ) {
      const flushedId = pendingDeleteIdRef.current
      clearTimeout(deleteTimerRef.current)
      deleteTimerRef.current = null
      pendingDeleteIdRef.current = null
      deleteTodo.mutate(flushedId)
    } else if (deleteTimerRef.current !== null) {
      clearTimeout(deleteTimerRef.current)
      deleteTimerRef.current = null
      pendingDeleteIdRef.current = null
    }

    pendingDeleteIdRef.current = id
    setDeletingId(id)
    deleteTimerRef.current = setTimeout(() => {
      deleteTimerRef.current = null
      pendingDeleteIdRef.current = null
      deleteTodo.mutate(id, {
        onSettled: () => {
          setDeletingId((current) => (current === id ? null : current))
        },
      })
    }, DELETE_FADE_MS)
  }

  const focusItem = (index: number) => {
    setRovingIndex(index)
    queueMicrotask(() => {
      itemRefs.current[index]?.focus()
    })
  }

  const handleRowKeyDown = (
    e: KeyboardEvent<HTMLLIElement>,
    index: number,
  ) => {
    if (e.key === 'ArrowDown') {
      e.preventDefault()
      if (index < todos.length - 1) focusItem(index + 1)
      return
    }
    if (e.key === 'ArrowUp') {
      e.preventDefault()
      if (index > 0) {
        focusItem(index - 1)
      } else {
        inputRef?.current?.focus()
      }
      return
    }
    if (e.key === ' ' || e.key === 'Enter') {
      e.preventDefault()
      const todo = todos[index]
      handleToggle(todo.id, !todo.completed)
      return
    }
    if (e.key === 'Delete' || e.key === 'Backspace') {
      e.preventDefault()
      handleDelete(todos[index].id)
    }
  }

  if (isLoading) return <LoadingState />
  if (isError && isFetching) return <LoadingState />
  if (isError) return <ErrorState onRetry={refetch} />
  if (todos.length === 0) return <EmptyState />

  return (
    <ul role="list" aria-label="Task list" className="divide-y divide-border">
      {todos.map((todo, index) => (
        <TodoItem
          key={todo.id}
          ref={(el) => {
            itemRefs.current[index] = el
          }}
          todo={todo}
          onToggle={handleToggle}
          onDelete={handleDelete}
          isExiting={deletingId === todo.id}
          tabIndex={index === rovingIndex ? 0 : -1}
          onRowKeyDown={(e) => handleRowKeyDown(e, index)}
        />
      ))}
    </ul>
  )
}

