import { AxeBuilder } from '@axe-core/playwright'
import type { Page } from '@playwright/test'

const FAIL_IMPACTS = new Set(['critical', 'serious'])

/**
 * Fails the test if axe reports any critical or serious violations.
 * Skips when the page has not navigated to an http(s) URL (e.g. unused page fixture).
 */
export async function assertNoCriticalOrSeriousViolations (page: Page) {
  const url = page.url()
  if (!url.startsWith('http')) return

  const results = await new AxeBuilder({ page }).analyze()
  const bad = results.violations.filter((v) =>
    v.impact != null && FAIL_IMPACTS.has(v.impact),
  )
  if (bad.length === 0) return

  const lines = bad.map(
    (v) => `  - ${v.id} [${v.impact}]: ${v.help} (${v.nodes.length} element(s))`,
  )
  throw new Error(
    `axe: ${bad.length} critical/serious violation(s):\n${lines.join('\n')}`,
  )
}

#!/usr/bin/env node
/**
 * Accessibility audit against a running dev server.
 * Usage: LIGHTHOUSE_URL=http://localhost:5173 node scripts/lighthouse-a11y.mjs
 * Requires Node 22+ (matches lighthouse@13 engines).
 */
import { writeFileSync } from 'node:fs'
import { tmpdir } from 'node:os'
import { join } from 'node:path'
import { pathToFileURL } from 'node:url'

const url = process.env['LIGHTHOUSE_URL'] ?? 'http://localhost:5173'
const minScore = Number(process.env['LIGHTHOUSE_MIN_A11Y_SCORE'] ?? 90) / 100

async function main () {
  const [{ default: lighthouse }, { launch }] = await Promise.all([
    import('lighthouse'),
    import('chrome-launcher'),
  ])

  const chrome = await launch({
    chromeFlags: ['--headless', '--no-sandbox', '--disable-gpu'],
  })

  try {
    const runnerResult = await lighthouse(url, {
      logLevel: process.env['CI'] ? 'error' : 'info',
      output: 'json',
      onlyCategories: ['accessibility'],
      port: chrome.port,
    })

    if (runnerResult == null || runnerResult.lhr == null) {
      throw new Error('Lighthouse returned no result')
    }

    const lhr = runnerResult.lhr
    const cat = lhr.categories?.accessibility
    const score = cat?.score
    if (score == null) {
      throw new Error('Lighthouse accessibility category score missing')
    }

    const outPath = join(tmpdir(), `lighthouse-a11y-${Date.now()}.json`)
    writeFileSync(outPath, lhr.report)

    const failedAudits = (cat.auditRefs ?? [])
      .map((ref) => {
        const audit = lhr.audits?.[ref.id]
        if (audit == null) return null
        if (audit.score == null) return null
        if (audit.score >= 1) return null
        return { id: ref.id, title: audit.title, description: audit.description }
      })
      .filter(Boolean)

    const pct = Math.round(score * 100)
    console.log(`Lighthouse accessibility score: ${pct} (min ${Math.round(minScore * 100)})`)
    console.log(`Report JSON: ${pathToFileURL(outPath).href}`)

    if (score < minScore) {
      throw new Error(
        `Accessibility score ${pct} is below minimum ${Math.round(minScore * 100)}`,
      )
    }

    if (failedAudits.length > 0) {
      console.error('Failing accessibility audits:')
      for (const a of failedAudits) {
        console.error(`  - ${a.id}: ${a.title}`)
      }
      throw new Error(
        `${failedAudits.length} accessibility audit(s) did not pass (score < 100%)`,
      )
    }

    console.log('Lighthouse accessibility gate passed (score + audits).')
  } finally {
    await chrome.kill()
  }
}

main().catch((err) => {
  console.error(err)
  process.exitCode = 1
})

