const DELETE_FADE_MS = 200

function getDeleteFadeDelayMs () {
  if (typeof window === 'undefined') return DELETE_FADE_MS
  return window.matchMedia('(prefers-reduced-motion: reduce)').matches
    ? 0
    : DELETE_FADE_MS
}

